@@ -0,0 +1,86 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://github.com/Dicklesworthstone/doodlestein_self_releaser/schemas/check-details.json",
+  "title": "DSR Check Details",
+  "description": "Details payload for 'dsr check' command",
+  "type": "object",
+  "required": ["repos_checked", "throttled", "healthy", "threshold_seconds"],
+  "properties": {
+    "repos_checked": {
+      "type": "array",
+      "items": { "type": "string" },
+      "description": "List of repositories that were checked"
+    },
+    "threshold_seconds": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "Queue time threshold used for detection"
+    },
+    "throttled": {
+      "type": "array",
+      "items": { "$ref": "#/$defs/throttled_repo" },
+      "description": "Repositories with throttled workflows"
+    },
+    "healthy": {
+      "type": "array",
+      "items": { "type": "string" },
+      "description": "Repositories with healthy queue times"
+    },
+    "skipped": {
+      "type": "array",
+      "items": {
+        "type": "object",
+        "properties": {
+          "repo": { "type": "string" },
+          "reason": { "type": "string" }
+        }
+      },
+      "description": "Repositories that were skipped"
+    }
+  },
+  "$defs": {
+    "throttled_repo": {
+      "type": "object",
+      "required": ["repo", "workflow", "run_id", "queue_time_seconds"],
+      "properties": {
+        "repo": {
+          "type": "string",
+          "description": "Repository name (owner/repo or short name)"
+        },
+        "workflow": {
+          "type": "string",
+          "description": "Workflow file name"
+        },
+        "run_id": {
+          "type": "integer",
+          "description": "GitHub Actions run ID"
+        },
+        "queue_time_seconds": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Time spent in queue"
+        },
+        "status": {
+          "type": "string",
+          "enum": ["queued", "in_progress", "completed"],
+          "description": "Current workflow status"
+        },
+        "created_at": {
+          "type": "string",
+          "format": "date-time",
+          "description": "When the run was created"
+        },
+        "started_at": {
+          "type": "string",
+          "format": "date-time",
+          "description": "When the run started (if started)"
+        },
+        "html_url": {
+          "type": "string",
+          "format": "uri",
+          "description": "URL to the workflow run"
+        }
+      }
+    }
+  }
+}

@@ -0,0 +1,74 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://github.com/Dicklesworthstone/doodlestein_self_releaser/schemas/doctor-details.json",
+  "title": "DSR Doctor Details",
+  "description": "Details payload for 'dsr doctor' command",
+  "type": "object",
+  "required": ["checks", "overall_status"],
+  "properties": {
+    "overall_status": {
+      "type": "string",
+      "enum": ["healthy", "degraded", "unhealthy"],
+      "description": "Overall system status"
+    },
+    "checks": {
+      "type": "array",
+      "items": { "$ref": "#/$defs/health_check" },
+      "description": "Individual health checks"
+    },
+    "recommendations": {
+      "type": "array",
+      "items": { "type": "string" },
+      "description": "Recommended actions"
+    },
+    "system_info": {
+      "type": "object",
+      "properties": {
+        "os": { "type": "string" },
+        "arch": { "type": "string" },
+        "hostname": { "type": "string" },
+        "dsr_version": { "type": "string" }
+      },
+      "description": "System information"
+    }
+  },
+  "$defs": {
+    "health_check": {
+      "type": "object",
+      "required": ["name", "status"],
+      "properties": {
+        "name": {
+          "type": "string",
+          "description": "Check name"
+        },
+        "category": {
+          "type": "string",
+          "enum": ["auth", "tool", "network", "config"],
+          "description": "Check category"
+        },
+        "status": {
+          "type": "string",
+          "enum": ["pass", "warn", "fail", "skip"],
+          "description": "Check result"
+        },
+        "message": {
+          "type": "string",
+          "description": "Status message"
+        },
+        "details": {
+          "type": "object",
+          "description": "Additional check details"
+        },
+        "fix_command": {
+          "type": "string",
+          "description": "Command to fix the issue"
+        },
+        "duration_ms": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Check duration"
+        }
+      }
+    }
+  }
+}

@@ -0,0 +1,118 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://github.com/Dicklesworthstone/doodlestein_self_releaser/schemas/release-details.json",
+  "title": "DSR Release Details",
+  "description": "Details payload for 'dsr release' command",
+  "type": "object",
+  "required": ["repo", "version", "tag"],
+  "properties": {
+    "repo": {
+      "type": "string",
+      "description": "Repository name"
+    },
+    "version": {
+      "type": "string",
+      "description": "Release version"
+    },
+    "tag": {
+      "type": "string",
+      "description": "Git tag name"
+    },
+    "release_id": {
+      "type": "integer",
+      "description": "GitHub release ID"
+    },
+    "release_url": {
+      "type": "string",
+      "format": "uri",
+      "description": "URL to the GitHub release"
+    },
+    "upload_url": {
+      "type": "string",
+      "description": "GitHub upload URL for assets"
+    },
+    "draft": {
+      "type": "boolean",
+      "description": "Whether release is a draft"
+    },
+    "prerelease": {
+      "type": "boolean",
+      "description": "Whether release is a prerelease"
+    },
+    "assets_uploaded": {
+      "type": "array",
+      "items": { "$ref": "#/$defs/uploaded_asset" },
+      "description": "List of uploaded assets"
+    },
+    "checksums": {
+      "type": "object",
+      "properties": {
+        "published": { "type": "boolean" },
+        "filename": { "type": "string" },
+        "algorithm": { "type": "string", "enum": ["sha256", "sha512"] }
+      },
+      "description": "Checksum file details"
+    },
+    "signatures": {
+      "type": "object",
+      "properties": {
+        "published": { "type": "boolean" },
+        "method": { "type": "string", "enum": ["minisign", "cosign", "gpg"] },
+        "key_id": { "type": "string" }
+      },
+      "description": "Signature details"
+    },
+    "sbom": {
+      "type": "object",
+      "properties": {
+        "published": { "type": "boolean" },
+        "format": { "type": "string", "enum": ["spdx", "cyclonedx"] },
+        "filename": { "type": "string" }
+      },
+      "description": "SBOM details"
+    },
+    "provenance": {
+      "type": "object",
+      "properties": {
+        "published": { "type": "boolean" },
+        "slsa_level": { "type": "integer", "minimum": 0, "maximum": 4 }
+      },
+      "description": "SLSA provenance attestation"
+    },
+    "release_notes": {
+      "type": "string",
+      "description": "Generated release notes"
+    }
+  },
+  "$defs": {
+    "uploaded_asset": {
+      "type": "object",
+      "required": ["name", "size_bytes", "download_url"],
+      "properties": {
+        "name": {
+          "type": "string",
+          "description": "Asset filename"
+        },
+        "size_bytes": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Asset size"
+        },
+        "content_type": {
+          "type": "string",
+          "description": "MIME type"
+        },
+        "download_url": {
+          "type": "string",
+          "format": "uri",
+          "description": "Direct download URL"
+        },
+        "download_count": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Download count (if available)"
+        }
+      }
+    }
+  }
+}
